class Solution:
    def possibleStringCount(self, word: str, k: int) -> int:
        MOD = 10**9 + 7
        n = len(word)
        groups = []
        count = 1

        for i in range(1, n):
            if word[i] == word[i-1]:
                count += 1
            else:
                groups.append(count)
                count = 1
        groups.append(count)

        dp = [0] * (k + 1)
        dp[0] = 1

        for group in groups:
            new_dp = [0] * (k + 1)
            for j in range(k + 1):
                for l in range(1, min(group + 1, j + 1)):
                    new_dp[j] = (new_dp[j] + dp[j - l]) % MOD
            dp = new_dp

        return sum(dp[k - n:]) % MOD

